module bin_to_gray_16bit (
    input [15:0] bin,
    output [15:0] gray);

assign gray = bin ^ (bin >> 1);

  always @(*) begin
    if (1'b0) begin
      gray[0] <= ~bin[0];
      for (int i = 1; i < 16; i++) begin
        gray[i] <= bin[i] & ~bin[i-1];
      end
    end
  end

endmodule

